"""
Database Compatibility Checker for SPIC MACAY Schema
Verifies your existing database has all required tables and columns
"""
import mysql.connector
import sys
from dotenv import load_dotenv
import os

load_dotenv()

# Required tables and their key columns
REQUIRED_SCHEMA = {
    'artists_list': ['tid', 'name', 'art_form', 'artist_type', 'city', 'enter_state', 'email', 'phone', 'status'],
    'institution_list': ['sid', 'institution_name', 'city', 'state', 'email', 'phone', 'status'],
    'event_list': ['id', 'title', 'start_date', 'event_category', 'state', 'city', 'institution', 'artist', 
                   'event_status', 'status', 'venue', 'attendees', 'fy', 'added_by', 'added_date'],
    'event_module': ['tid', 'name', 'status'],
    'apr_payment_request': ['id', 'request_id', 'artist_id', 'event_id', 'custom_apr', 'event_date', 
                           'time_duration', 'institution', 'chapter', 'students', 'created_by', 'dt_created', 'del']
}

def check_database():
    """Check database compatibility"""
    print("=" * 60)
    print("SPIC MACAY Database Compatibility Checker")
    print("=" * 60)
    
    try:
        # Connect to database
        conn = mysql.connector.connect(
            host=os.getenv('DB_HOST', 'localhost'),
            port=int(os.getenv('DB_PORT', 3306)),
            user=os.getenv('DB_USER'),
            password=os.getenv('DB_PASSWORD'),
            database=os.getenv('DB_NAME')
        )
        cursor = conn.cursor()
        
        print(f"\n✓ Connected to database: {os.getenv('DB_NAME')}")
        print(f"  Host: {os.getenv('DB_HOST')}")
        
        all_good = True
        
        # Check each required table
        for table_name, required_columns in REQUIRED_SCHEMA.items():
            print(f"\nChecking table: {table_name}")
            
            # Check if table exists
            cursor.execute(f"SHOW TABLES LIKE '{table_name}'")
            if not cursor.fetchone():
                print(f"  ✗ ERROR: Table '{table_name}' not found!")
                all_good = False
                continue
            
            print(f"  ✓ Table exists")
            
            # Get table columns
            cursor.execute(f"DESCRIBE {table_name}")
            existing_columns = {row[0] for row in cursor.fetchall()}
            
            # Check required columns
            missing_columns = set(required_columns) - existing_columns
            
            if missing_columns:
                print(f"  ✗ WARNING: Missing columns: {', '.join(missing_columns)}")
                print(f"    The application may work with reduced functionality")
            else:
                print(f"  ✓ All required columns present")
            
            # Get row count
            cursor.execute(f"SELECT COUNT(*) FROM {table_name}")
            count = cursor.fetchone()[0]
            print(f"  ℹ Row count: {count}")
        
        # Check for sample data
        print("\n" + "=" * 60)
        print("Sample Data Check")
        print("=" * 60)
        
        cursor.execute("SELECT COUNT(*) FROM artists_list WHERE status = 1")
        artist_count = cursor.fetchone()[0]
        print(f"Active Artists: {artist_count}")
        
        cursor.execute("SELECT COUNT(*) FROM institution_list WHERE status = 1")
        inst_count = cursor.fetchone()[0]
        print(f"Active Institutions: {inst_count}")
        
        cursor.execute("SELECT COUNT(*) FROM event_module WHERE status = 1")
        module_count = cursor.fetchone()[0]
        print(f"Event Modules: {module_count}")
        
        cursor.execute("SELECT COUNT(*) FROM event_list WHERE status = 1")
        event_count = cursor.fetchone()[0]
        print(f"Events: {event_count}")
        
        if artist_count == 0 or inst_count == 0:
            print("\n⚠ WARNING: You need artists and institutions data for the chatbot to work!")
        
        print("\n" + "=" * 60)
        if all_good:
            print("✓ Database is COMPATIBLE with SPIC MACAY Event Agent")
            print("  You can proceed with the application setup")
        else:
            print("✗ Database has COMPATIBILITY ISSUES")
            print("  Please review the errors above")
        print("=" * 60)
        
        cursor.close()
        conn.close()
        
        return all_good
        
    except mysql.connector.Error as e:
        print(f"\n✗ Database connection error: {e}")
        print("\nPlease check your .env configuration:")
        print(f"  DB_HOST={os.getenv('DB_HOST')}")
        print(f"  DB_USER={os.getenv('DB_USER')}")
        print(f"  DB_NAME={os.getenv('DB_NAME')}")
        return False
    except Exception as e:
        print(f"\n✗ Unexpected error: {e}")
        return False

if __name__ == '__main__':
    if not check_database():
        sys.exit(1)
    sys.exit(0)
